import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"北京植物园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/botanical-garden.md","filePath":"parks/botanical-garden.md","lastUpdated":1784773307000}'),n={name:"parks/botanical-garden.md"};function d(s,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="北京植物园" tabindex="-1">北京植物园 <a class="header-anchor" href="#北京植物园" aria-label="Permalink to &quot;北京植物园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-CMNxYfonRpc?w=1200" alt="北京植物园"></p><blockquote><p>&quot;万木争荣，百花争艳，植物王国的奇妙之旅。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北京植物园位于北京市海淀区香山脚下，是一座集科研、科普、游览于一体的大型植物园。植物园占地面积约400公顷，收集了国内外植物约1.5万种，是亚洲最大的植物园之一。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-20:00（旺季），7:00-17:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">10元（旺季），5元（淡季）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春季（赏花）、秋季（赏叶）</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁西郊线植物园站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市海淀区香山南辛村20号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="规划建设" tabindex="-1">规划建设 <a class="header-anchor" href="#规划建设" aria-label="Permalink to &quot;规划建设&quot;">​</a></h3><p>北京植物园始建于1956年，是中国最早建立的植物园之一。植物园的建设得到了苏联专家的帮助，采用了当时世界上最先进的植物园设计理念。</p><h4 id="发展历程" tabindex="-1">发展历程 <a class="header-anchor" href="#发展历程" aria-label="Permalink to &quot;发展历程&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1956年</td><td style="text-align:left;">北京植物园成立</td></tr><tr><td style="text-align:left;">1980年代</td><td style="text-align:left;">植物园进行扩建，增加了温室和专类园</td></tr><tr><td style="text-align:left;">2000年</td><td style="text-align:left;">植物园被评为AAAA级景区</td></tr><tr><td style="text-align:left;">2008年</td><td style="text-align:left;">植物园进行了大规模的改造升级</td></tr><tr><td style="text-align:left;">2020年</td><td style="text-align:left;">植物园进行了数字化升级</td></tr></tbody></table><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="温室群" tabindex="-1">温室群 <a class="header-anchor" href="#温室群" aria-label="Permalink to &quot;温室群&quot;">​</a></h3><p>植物园的温室群是亚洲最大的温室群之一，展示了世界各地的珍稀植物。</p><h4 id="温室分区" tabindex="-1">温室分区 <a class="header-anchor" href="#温室分区" aria-label="Permalink to &quot;温室分区&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">温室</th><th style="text-align:left;">特色</th><th style="text-align:left;">植物种类</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>热带植物温室</strong></td><td style="text-align:left;">热带雨林景观</td><td style="text-align:left;">热带植物</td></tr><tr><td style="text-align:left;"><strong>沙漠植物温室</strong></td><td style="text-align:left;">沙漠景观</td><td style="text-align:left;">仙人掌、多肉植物</td></tr><tr><td style="text-align:left;"><strong>高山植物温室</strong></td><td style="text-align:left;">高山景观</td><td style="text-align:left;">高山植物</td></tr><tr><td style="text-align:left;"><strong>水生植物温室</strong></td><td style="text-align:left;">水生景观</td><td style="text-align:left;">水生植物</td></tr></tbody></table><h3 id="专类园" tabindex="-1">专类园 <a class="header-anchor" href="#专类园" aria-label="Permalink to &quot;专类园&quot;">​</a></h3><p>植物园内设有多个专类园，展示了不同种类的植物。</p><h4 id="主要专类园" tabindex="-1">主要专类园 <a class="header-anchor" href="#主要专类园" aria-label="Permalink to &quot;主要专类园&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">专类园</th><th style="text-align:left;">特色</th><th style="text-align:left;">最佳观赏期</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>牡丹园</strong></td><td style="text-align:left;">国花牡丹</td><td style="text-align:left;">4-5月</td></tr><tr><td style="text-align:left;"><strong>芍药园</strong></td><td style="text-align:left;">芍药花</td><td style="text-align:left;">5月</td></tr><tr><td style="text-align:left;"><strong>月季园</strong></td><td style="text-align:left;">月季花</td><td style="text-align:left;">5-10月</td></tr><tr><td style="text-align:left;"><strong>丁香园</strong></td><td style="text-align:left;">丁香花</td><td style="text-align:left;">4-5月</td></tr><tr><td style="text-align:left;"><strong>碧桃园</strong></td><td style="text-align:left;">碧桃花</td><td style="text-align:left;">3-4月</td></tr><tr><td style="text-align:left;"><strong>海棠园</strong></td><td style="text-align:left;">海棠花</td><td style="text-align:left;">4-5月</td></tr><tr><td style="text-align:left;"><strong>木兰园</strong></td><td style="text-align:left;">玉兰花</td><td style="text-align:left;">3-4月</td></tr><tr><td style="text-align:left;"><strong>宿根花卉园</strong></td><td style="text-align:left;">宿根花卉</td><td style="text-align:left;">夏秋</td></tr><tr><td style="text-align:left;"><strong>竹园</strong></td><td style="text-align:left;">竹子</td><td style="text-align:left;">四季</td></tr><tr><td style="text-align:left;"><strong>梅园</strong></td><td style="text-align:left;">梅花</td><td style="text-align:left;">2-3月</td></tr></tbody></table><h3 id="卧佛寺" tabindex="-1">卧佛寺 <a class="header-anchor" href="#卧佛寺" aria-label="Permalink to &quot;卧佛寺&quot;">​</a></h3><p>卧佛寺位于植物园内，是一座历史悠久的佛教寺院。</p><h4 id="主要看点" tabindex="-1">主要看点 <a class="header-anchor" href="#主要看点" aria-label="Permalink to &quot;主要看点&quot;">​</a></h4><ul><li><strong>卧佛</strong>：长5米余的铜铸卧佛</li><li><strong>千年古树</strong>：寺内有多棵千年古树</li><li><strong>古建筑</strong>：保存完好的古建筑群</li></ul><h3 id="曹雪芹纪念馆" tabindex="-1">曹雪芹纪念馆 <a class="header-anchor" href="#曹雪芹纪念馆" aria-label="Permalink to &quot;曹雪芹纪念馆&quot;">​</a></h3><p>曹雪芹纪念馆位于植物园内，是纪念《红楼梦》作者曹雪芹的专题纪念馆。</p><h4 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><ul><li><strong>曹雪芹生平</strong>：展示曹雪芹的生平事迹</li><li><strong>《红楼梦》创作</strong>：展示《红楼梦》的创作过程</li><li><strong>红学研究</strong>：展示红学研究的成果</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约4小时）</strong>：</p><p>入口 → 温室群 → 牡丹园 → 芍药园 → 月季园 → 卧佛寺 → 曹雪芹纪念馆 → 出口</p><p><strong>春季赏花路线（约半天）</strong>：</p><p>入口 → 梅园 → 木兰园 → 碧桃园 → 海棠园 → 牡丹园 → 芍药园 → 丁香园 → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：春季（4-5月）和秋季（10-11月）是最佳观赏期</li><li><strong>温室参观</strong>：温室内温度较高，建议适当减少衣物</li><li><strong>拍照位置</strong>：温室群、专类园都是绝佳拍照点</li><li><strong>交通建议</strong>：建议乘坐公共交通，自驾停车困难</li><li><strong>周边游览</strong>：可以与香山公园、碧云寺一起游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">西郊线植物园站，步行约5分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">331、563、运通112路北京植物园站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;北京植物园&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">香山公园</td><td style="text-align:center;">约2公里</td><td style="text-align:left;">红叶观赏</td></tr><tr><td style="text-align:left;">碧云寺</td><td style="text-align:center;">约3公里</td><td style="text-align:left;">佛教寺院</td></tr><tr><td style="text-align:left;">颐和园</td><td style="text-align:center;">约5公里</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">玉泉山</td><td style="text-align:center;">约3公里</td><td style="text-align:left;">名胜古迹</td></tr></tbody></table><hr><p>** 地址**：北京市海淀区香山南辛村20号 <strong>🚇 地铁</strong>：西郊线植物园站 <strong>📞 电话</strong>：010-62591283 <strong>🌐 官网</strong>：<a href="http://www.beijingbotanicalgarden.com.cn" target="_blank" rel="noreferrer">www.beijingbotanicalgarden.com.cn</a></p><p><strong>💡 Tips</strong>：北京植物园的温室群非常值得参观，建议预留足够的时间。春季赏花时人较多，建议早去。</p>',44)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
